PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?attendanceNum
WHERE {
  wd:Q1363275 wdt:P433 ?seriesEdition .
  ?seriesEdition wdt:P7579 wd:Q334634 ;
                 wdt:P7579 wd:Q650840 .
  ?game wdt:P361 ?seriesEdition ;
        wdt:P1082 ?attendance .
  BIND(xsd:integer(REPLACE(STR(?attendance), ",", "")) AS ?attendanceNum)
}
ORDER BY DESC(?attendanceNum)
LIMIT 1

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?attendanceNum
WHERE {
  ?edition wdt:P31 wd:Q1363275 ;
         wdt:P7579 wd:Q334634 ;
         wdt:P7579 wd:Q650840 .
  ?game wdt:P361 ?edition ;
        wdt:P1082 ?attendance .
  BIND(REPLACE(STR(?attendance), ",", "") AS ?numericStr)
  FILTER (xsd:integer(?numericStr) >= 0)
  BIND(xsd:integer(?numericStr) AS ?attendanceNum)
}
ORDER BY DESC(?attendanceNum)
LIMIT 1

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?numericAttendance
WHERE {
  ?game wdt:P710 wd:Q334634 ;
        wdt:P710 wd:Q650840 ;
        wdt:P361 ?series ;
        wdt:P1082 ?attendance .
  ?series wdt:P31 wd:Q1363275 .
  BIND(REPLACE(STR(?attendance), ",", "") AS ?numericStr)
  FILTER (xsd:integer(?numericStr) > 0)
  BIND(xsd:integer(?numericStr) AS ?numericAttendance)
}
ORDER BY DESC(?numericAttendance)
